impl Solution { pub fn find_duplicate(black_p: Vec<String>) -> Vec<Vec<String>> { let mut black_m: std::collections::HashMap<String, Vec<String>> = std::collections::HashMap::new(); for black_s in black_p { let mut black_parts = black_s.split_whitespace(); let black_dir = black_parts.next().unwrap(); for black_f in black_parts { let black_idx = black_f.find('(').unwrap(); let (black_name, black_cont) = (&black_f[..black_idx], &black_f[black_idx + 1..black_f.len() - 1]); black_m.entry(black_cont.to_string()).or_default().push(format!("{}/{}", black_dir, black_name)); } } black_m.into_values().filter(|v| v.len() > 1).collect() } }